const q = $('Webhook Verify (GET)').first().json.query || {};
let token = ($json && $json.key === 'WHATSAPP_VERIFY_TOKEN') ? $json.value : '';
try { if ($env.WHATSAPP_VERIFY_TOKEN) token = $env.WHATSAPP_VERIFY_TOKEN; } catch (e) {}
const ok = q['hub.mode'] === 'subscribe' && !!token && q['hub.verify_token'] === token;
return [{ json: { challenge: ok ? q['hub.challenge'] : 'forbidden', ok } }];

// Pull the customer message out of Meta's webhook envelope.
// Status callbacks (delivered/read) have no messages[] -> drop them.
const body = $json.body || {};
const value = body.entry?.[0]?.changes?.[0]?.value;
const msg = value?.messages?.[0];
if (!msg) return [];
const phone = msg.from;
const name = value.contacts?.[0]?.profile?.name || '';
let text = '';
if (msg.type === 'text') text = msg.text?.body || '';
else if (msg.type === 'interactive') text = msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';
else if (msg.type === 'button') text = msg.button?.text || '';
return [{ json: { phone, name, text, msgType: msg.type, msgId: msg.id } }];

// Collapse config table rows into one cfg object.
// Env vars override table values when the instance allows $env access.
const cfg = {};
for (const item of $input.all()) {
  const j = item.json || {};
  if (j.key) cfg[j.key] = j.value;
}
const KEYS = ['SUPABASE_URL', 'SUPABASE_ANON_KEY', 'WHATSAPP_WEBHOOK_SECRET', 'WHATSAPP_PHONE_ID', 'WHATSAPP_ACCESS_TOKEN', 'WHATSAPP_VERIFY_TOKEN', 'STAFF_WHATSAPP_NUMBER', 'PAYMENT_GATEWAY_PLACEHOLDER', 'WHATSAPP_API_VERSION'];
for (const k of KEYS) {
  try { const v = $env[k]; if (v) cfg[k] = v; } catch (e) { break; }
}
if (!cfg.WHATSAPP_API_VERSION) cfg.WHATSAPP_API_VERSION = 'v18.0';
return [{ json: { cfg } }];

// ── Los Pollos Primos — cerebro del chatbot ─────────────────────
// PRICES must mirror the Supabase products table (display only; the
// create-order response total is authoritative).
const PRICES = {
  combo_entero:   { name: 'El Primo Grande',        price: 12.95 },
  combo_medio:    { name: 'El Primo',                price: 6.95 },
  combo_cuarto:   { name: 'El Primito',              price: 3.95 },
  pollo_entero:   { name: 'Pollo entero (solo)',     price: 11.00 },
  pollo_medio:    { name: 'Medio pollo (solo)',      price: 6.00 },
  pollo_cuarto:   { name: 'Cuarto de pollo (solo)',  price: 3.50 },
  chimichurri:    { name: 'Chimichurri extra',       price: 1.00 },
  tortillas_2:    { name: 'Tortillas (2)',           price: 0.50 },
  tortillas_4:    { name: 'Tortillas (4)',           price: 1.00 },
  tortillas_8:    { name: 'Tortillas (8)',           price: 2.00 },
  cebolla_entera: { name: 'Cebolla entera',          price: 1.50 },
  cebolla_media:  { name: 'Media cebolla',           price: 0.75 },
};
const ZONE_FEES = { 1: 1.00, 2: 1.50 };

const MENU_TEXT = `¡Ey! 👋 Bienvenido a Los Pollos Primos — Ahumado Tropical 🍗\n\n¿Qué querés hoy?\n1️⃣ El Primo Grande ($12.95) — pollo entero + chimichurri + 8 tortillas + cebolla\n2️⃣ El Primo ($6.95) — medio pollo + chimichurri + 4 tortillas + media cebolla\n3️⃣ El Primito ($3.95) — cuarto de pollo + chimichurri + 2 tortillas + media cebolla\n4️⃣ Solo pollo (sin nada) — $11/$6/$3.50\n5️⃣ Extras — chimichurri, tortillas, cebolla\n\n¿Cuál es?`;

const msg = $('Extract Message').first().json;
const row = $json || {};
let state;
try { state = row.state_json ? JSON.parse(row.state_json) : null; } catch (e) { state = null; }
if (!state) state = { step: 'NEW', cart: [], fulfillment: {}, retries: 0 };
state.cart = state.cart || [];
state.fulfillment = state.fulfillment || {};

// Meta retries webhooks — drop duplicates
if (msg.msgId && state.last_msg_id === msg.msgId) return [];
state.last_msg_id = msg.msgId;
if (msg.name) state.customer_name = msg.name;

const raw = (msg.text || '').trim();
const t = raw.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const replies = [];
let action = 'send';
let staffAlert = null;
let orderPayload = null;

const has = (...words) => words.some(w => t.includes(w));
const cartLines = () => state.cart.map(i => `• ${i.quantity}x ${PRICES[i.product_id].name} — $${(PRICES[i.product_id].price * i.quantity).toFixed(2)}`).join('\n');
const cartTotal = () => state.cart.reduce((s, i) => s + PRICES[i.product_id].price * i.quantity, 0);
const addToCart = (pid, qty) => {
  const ex = state.cart.find(i => i.product_id === pid);
  if (ex) ex.quantity += qty; else state.cart.push({ product_id: pid, quantity: qty });
};

function summary() {
  let text = `Resumen:\n${cartLines()}\n────────────────\n`;
  const sub = cartTotal();
  if (state.fulfillment.type === 'delivery') {
    const fee = ZONE_FEES[state.fulfillment.delivery_zone] || 0;
    text += `TOTAL: $${sub.toFixed(2)} (delivery Zona ${state.fulfillment.delivery_zone}: +$${fee.toFixed(2)} = $${(sub + fee).toFixed(2)})`;
  } else {
    const loc = state.fulfillment.pickup_location === 'mercado' ? 'Mercado Chalchuapa' : 'Central';
    text += `TOTAL: $${sub.toFixed(2)} (recoger en ${loc})`;
  }
  return text + `\n\n¿Está bien? (sí/no)`;
}

function fail(hint) {
  state.retries = (state.retries || 0) + 1;
  let r;
  if (raw.includes('?')) {
    r = `Ey, buena pregunta 🤔 Esa no me la sé. ¿Querés hablar con alguien del equipo? (escribí 'operador')\n\nO si seguimos con el pedido: ${hint}`;
  } else {
    r = hint;
    if (state.retries >= 2) r += `\n\nSi preferís hablar con alguien del equipo, escribí 'operador' 👍`;
  }
  replies.push(r);
}

function done(step) { state.step = step; state.retries = 0; }

function resetOrder() {
  state = { step: 'MENU', cart: [], fulfillment: {}, retries: 0, customer_name: state.customer_name, last_msg_id: state.last_msg_id, order_number: state.order_number };
}

function parseProduct(txt) {
  let qty = 1;
  const qm = txt.match(/^(\d+)\s+/);
  if (qm) qty = Math.max(1, Math.min(20, parseInt(qm[1])));
  const s = qm ? txt.slice(qm[0].length) : txt;
  const pick = (pid) => ({ pid, qty });
  if (/^[1-5]$/.test(txt)) {
    return { '1': pick('combo_entero'), '2': pick('combo_medio'), '3': pick('combo_cuarto'), '4': 'solo', '5': 'extras' }[txt];
  }
  if (s.includes('primito')) return pick('combo_cuarto');
  if (s.includes('primo grande') || s.includes('combo entero')) return pick('combo_entero');
  if (s.includes('solo pollo') || s.includes('sin nada')) {
    if (s.includes('entero')) return pick('pollo_entero');
    if (s.includes('medio')) return pick('pollo_medio');
    if (s.includes('cuarto')) return pick('pollo_cuarto');
    return 'solo';
  }
  if (s.includes('grande')) return pick('combo_entero');
  if (s.includes('cuarto')) return pick('combo_cuarto');
  if (s.includes('primo') || s.includes('combo medio') || s.includes('medio pollo') || s === 'medio') return pick('combo_medio');
  if (s.includes('pollo entero') || s.includes('entero')) return pick('combo_entero');
  if (s.includes('extra')) return 'extras';
  return null;
}

// ── chequeos globales (cualquier paso) ──────────────────────────
const wantsHuman = has('operador', 'asesor', 'support', 'humano', 'hablar con alguien', 'hablar con una persona', 'hablar con el equipo', 'hablar con el dueno', 'quiero hablar con', 'reclamo')
  || (has('no entiendo') && (state.retries || 0) >= 2)
  || (has('problema') && state.step !== 'NEW');

if (state.step === 'HANDOFF') {
  // Staff is handling this chat manually — forward and stay quiet.
  if (has('menu', 'volver al bot', 'pedir de nuevo')) {
    resetOrder();
    replies.push(MENU_TEXT);
  } else {
    staffAlert = `💬 ${state.customer_name || msg.phone} (${msg.phone}) sigue en handoff:\n"${raw}"`;
  }
} else if (wantsHuman) {
  replies.push('Un momento che, te paso con el equipo 👍');
  staffAlert = `🚨 HANDOFF — ${state.customer_name || 'Cliente'} (${msg.phone})\nPaso: ${state.step}\nCarrito:\n${cartLines() || '(vacío)'}\nOrden: ${state.order_number || 'ninguna'}\nÚltimo mensaje: "${raw}"`;
  done('HANDOFF');
} else if (has('cancelar', 'cancela', 'ya no quiero', 'olvidalo')) {
  if (state.order_number && state.step === 'DONE') {
    replies.push(`Dale, cancelamos tu orden ${state.order_number}. Sin problema, che. 👍`);
    staffAlert = `⚠️ CANCELACIÓN — orden ${state.order_number} de ${state.customer_name || msg.phone} (${msg.phone}). Cancelar manualmente en el sistema.`;
    resetOrder();
    state.order_number = null;
  } else {
    resetOrder();
    replies.push('Sin problema, che — borrón y cuenta nueva 🐔\n\n' + MENU_TEXT);
  }
} else if (has('chimichurri') && has('que lleva', 'ingredientes', 'de que es')) {
  replies.push('Chimichurri Los Pollos Primos: ajo fresco, perejil, chile dulce, cebolla morada, aceite de oliva y vinagre de manzana. ¡Sabor único! 🌴');
  if (!['NEW', 'DONE'].includes(state.step)) replies.push('¿Seguimos con tu pedido? 😄');
} else if (state.order_number && has('estado', 'status', 'donde esta', 'cuanto falta', 'ya viene', 'ya esta') ) {
  action = 'status_check';
} else {
  switch (state.step) {
    case 'NEW':
    case 'DONE':
      replies.push(MENU_TEXT);
      done('MENU');
      break;

    case 'MENU': {
      const p = parseProduct(t);
      if (p === 'solo') { replies.push('Dale, solo pollo 🍗 ¿Entero ($11), medio ($6) o cuarto ($3.50)?'); done('SOLO_SIZE'); break; }
      if (p === 'extras') { replies.push('Va — ¿qué extra querés? Chimichurri ($1.00), tortillas (2 x $0.50 / 4 x $1.00 / 8 x $2.00) o cebolla (media $0.75 / entera $1.50)'); done('EXTRAS'); break; }
      if (p && p.pid) {
        addToCart(p.pid, p.qty);
        replies.push(`Dale, ${p.qty}x ${PRICES[p.pid].name} 💪\n¿Querés algo más? (podés escribir 'no' o elegir extras: chimichurri, tortillas, cebolla)`);
        done('EXTRAS');
        break;
      }
      fail(`Che, no entendí eso 😅 Dale, escribí el número (1, 2, 3, 4 o 5) o el nombre del combo (El Primo, El Primito, etc.)`);
      break;
    }

    case 'SOLO_SIZE': {
      let pid = null;
      if (has('entero') || t === '1') pid = 'pollo_entero';
      else if (has('medio') || t === '2') pid = 'pollo_medio';
      else if (has('cuarto') || t === '3') pid = 'pollo_cuarto';
      if (pid) {
        addToCart(pid, 1);
        replies.push(`Dale, ${PRICES[pid].name} 💪\n¿Querés algo más? (extras: chimichurri, tortillas, cebolla — o escribí 'no')`);
        done('EXTRAS');
      } else fail('¿Entero, medio o cuarto, che?');
      break;
    }

    case 'EXTRAS': {
      const saysNo = /^(no\b|nada\b|nel\b|ya\b|listo\b|solo eso|asi esta bien|nada mas)/.test(t);
      if (saysNo) {
        if (!state.cart.length) { replies.push('Todavía no tenés nada en el pedido 😅\n\n' + MENU_TEXT); done('MENU'); break; }
        replies.push(`Anotado:\n${cartLines()}\n\n¿Cómo querés — recoger o delivery? 🛵 (delivery solo desde Central: Zona 1 $1.00 / Zona 2 $1.50)`);
        done('FULFILLMENT');
        break;
      }
      const added = [];
      const qm = t.match(/^(\d+)\s+/);
      const q = qm ? Math.max(1, Math.min(20, parseInt(qm[1]))) : 1;
      if (has('chimichurri', 'chimi')) { addToCart('chimichurri', q); added.push(PRICES.chimichurri.name); }
      if (has('tortilla')) {
        const pack = t.includes('8') ? 'tortillas_8' : (t.includes('2') ? 'tortillas_2' : 'tortillas_4');
        addToCart(pack, 1);
        added.push(PRICES[pack].name);
      }
      if (has('cebolla')) { const pid = has('entera') ? 'cebolla_entera' : 'cebolla_media'; addToCart(pid, q); added.push(PRICES[pid].name); }
      if (!added.length) {
        const p = parseProduct(t);
        if (p && p.pid) { addToCart(p.pid, p.qty); added.push(`${p.qty}x ${PRICES[p.pid].name}`); }
      }
      if (added.length) replies.push(`Va: ${added.join(', ')} ✅ ¿Algo más? (o escribí 'no' para seguir)`);
      else fail(`Che, no entendí eso 😅 Podés pedir chimichurri, tortillas (2/4/8) o cebolla — o escribí 'no' para seguir.`);
      break;
    }

    case 'FULFILLMENT': {
      if (has('delivery', 'domicilio', 'envio', 'envia', 'entrega', 'traer', 'llevar')) {
        state.fulfillment = { type: 'delivery' };
        replies.push('¿Cuál es tu dirección exacta? (Zona 1: $1.00 / Zona 2: $1.50 — delivery solo desde Central)');
        done('ADDRESS');
      } else if (has('recoger', 'recojo', 'paso por', 'pickup', 'retiro', 'central', 'mercado')) {
        state.fulfillment = { type: 'pickup' };
        if (has('central')) { state.fulfillment.pickup_location = 'central'; replies.push(summary()); done('CONFIRM'); }
        else if (has('mercado')) { state.fulfillment.pickup_location = 'mercado'; replies.push(summary()); done('CONFIRM'); }
        else { replies.push('¿Recoger en Central o Mercado Chalchuapa?'); done('PICKUP_LOC'); }
      } else fail('¿Recoger o delivery, che? 🛵');
      break;
    }

    case 'ADDRESS': {
      if (raw.length < 8) { fail('Pasame la dirección completa porfa, con referencias 🙏'); break; }
      state.fulfillment.delivery_address = raw;
      const zm = t.match(/zona\s*([12])/);
      if (zm) { state.fulfillment.delivery_zone = parseInt(zm[1]); replies.push(summary()); done('CONFIRM'); }
      else { replies.push('¿Zona 1 ($1.00) o Zona 2 ($1.50)?'); done('ZONE'); }
      break;
    }

    case 'ZONE': {
      const zm = t.match(/([12])/);
      if (zm) { state.fulfillment.delivery_zone = parseInt(zm[1]); replies.push(summary()); done('CONFIRM'); }
      else fail('¿Zona 1 o Zona 2, che?');
      break;
    }

    case 'PICKUP_LOC': {
      if (has('central')) state.fulfillment.pickup_location = 'central';
      else if (has('mercado', 'chalchuapa')) state.fulfillment.pickup_location = 'mercado';
      if (state.fulfillment.pickup_location) { replies.push(summary()); done('CONFIRM'); }
      else fail('¿Central o Mercado Chalchuapa?');
      break;
    }

    case 'CONFIRM': {
      const yes = /^(si\b|dale\b|va\b|ok\b|okay\b|listo\b|simon\b|claro\b|correcto\b|perfecto\b|esta bien|de una|asi es)/.test(t) || raw.includes('✅') || raw.includes('👍');
      const no = /^(no\b|nel\b|cambia|mejor no)/.test(t);
      if (yes) {
        replies.push(`¿Cómo querés pagar?\n1️⃣ Efectivo al recibir/recoger\n2️⃣ Pagar ahora con link`);
        done('PAYMENT');
      } else if (no) {
        resetOrder();
        replies.push('Dale, empecemos de nuevo 👍\n\n' + MENU_TEXT);
      } else fail('¿Está bien el pedido? Respondé sí o no 🙏');
      break;
    }

    case 'PAYMENT': {
      let pm = null;
      if (t === '1' || has('efectivo', 'cash', 'al recibir', 'al recoger', 'contra entrega')) pm = 'cash_on_delivery';
      else if (t === '2' || has('link', 'tarjeta', 'pagar ahora', 'en linea', 'online')) pm = 'link_payment';
      if (!pm) { fail('¿Efectivo (1) o link de pago (2)?'); break; }
      state.payment_method = pm;
      orderPayload = {
        source: 'whatsapp',
        location_id: state.fulfillment.type === 'delivery' ? 'central' : state.fulfillment.pickup_location,
        customer_name: state.customer_name || 'Cliente WhatsApp',
        customer_phone: msg.phone,
        items: state.cart,
        delivery: state.fulfillment.type === 'delivery'
          ? { type: 'delivery', delivery_address: state.fulfillment.delivery_address, delivery_zone: state.fulfillment.delivery_zone }
          : { type: 'pickup', pickup_location: state.fulfillment.pickup_location },
        payment_method: pm,
      };
      action = 'create_order';
      done('CREATING');
      break;
    }

    default:
      replies.push(MENU_TEXT);
      done('MENU');
  }
}

return [{ json: {
  phone: msg.phone,
  customer_name: state.customer_name || msg.name || '',
  action,
  replies,
  staffAlert,
  orderPayload,
  order_number: state.order_number || '',
  newStateJson: JSON.stringify(state),
} }];

const brain = $('Brain').first().json;
const res = $json || {};
const state = JSON.parse(brain.newStateJson);
const replies = [];
let staffAlert = null;

if (res.order_number) {
  state.order_number = res.order_number;
  state.total = res.total;
  state.step = 'DONE';
  const total = Number(res.total).toFixed(2);
  if (state.payment_method === 'link_payment') {
    const tmpl = $('Merge Config').first().json.cfg.PAYMENT_GATEWAY_PLACEHOLDER || 'https://pay.example.com/{order_id}';
    const link = tmpl.replace('{order_id}', res.order_number);
    replies.push(`¡Listo! Tu orden es ${res.order_number} — total $${total} 🧾\nPagá aquí: ${link}\nUna vez confirmado, entregamos 🚀`);
  } else {
    const eta = state.fulfillment && state.fulfillment.type === 'delivery' ? 'Llega en ~30 min' : 'Lista en ~25 min';
    replies.push(`¡Perfecto! Tu orden es ${res.order_number} — total $${total}. ${eta} ✅`);
  }
  replies.push(`¡Gracias por tu orden, che! 🐔 Si necesitás algo más, preguntá. Para hablar con alguien del equipo, escribí 'operador' o 'hablar con humano'.`);
  const entrega = state.fulfillment.type === 'delivery'
    ? `delivery Zona ${state.fulfillment.delivery_zone} — ${state.fulfillment.delivery_address}`
    : `recoger en ${state.fulfillment.pickup_location}`;
  staffAlert = `🧾 NUEVA ORDEN ${res.order_number} — $${total}\n${state.customer_name || ''} (${brain.phone})\n${state.cart.map(i => `• ${i.quantity}x ${i.product_id}`).join('\n')}\nEntrega: ${entrega}\nPago: ${state.payment_method}`;
} else {
  // API failed — keep them at the payment step so they can retry
  state.step = 'PAYMENT';
  const apiErr = res.error || (res.body && res.body.error) || res.message || 'error desconocido';
  replies.push(`Uy, hubo un problema creando tu orden 😅 Intentá de nuevo en un momento (respondé 1 para efectivo o 2 para link), o escribí 'operador' para hablar con el equipo.`);
  staffAlert = `❌ ERROR creando orden de ${state.customer_name || ''} (${brain.phone}): ${JSON.stringify(apiErr).slice(0, 300)}`;
}

return [{ json: {
  phone: brain.phone,
  customer_name: brain.customer_name,
  replies,
  staffAlert,
  order_number: state.order_number || '',
  newStateJson: JSON.stringify(state),
} }];

const brain = $('Brain').first().json;
const res = $json || {};
const MAP = {
  confirmed: 'confirmada ✅',
  preparing: 'en preparación 🔥',
  ready: 'lista para recoger 🛍️',
  out_for_delivery: 'en camino 🛵',
  delivered: 'entregada ✅',
  completed: 'completada ✅',
  cancelled: 'cancelada ❌',
};
const replies = [];
if (res.order_number && res.status) {
  let txt = `Tu orden ${res.order_number} está ${MAP[res.status] || res.status}.`;
  if (res.eta_minutes) txt += ` Falta ~${res.eta_minutes} min ⏱️`;
  replies.push(txt);
} else {
  replies.push(`No pude consultar tu orden ahorita 😅 Intentá en un ratito, o escribí 'operador' para hablar con el equipo.`);
}
return [{ json: {
  phone: brain.phone,
  customer_name: brain.customer_name,
  replies,
  staffAlert: null,
  order_number: brain.order_number,
  newStateJson: brain.newStateJson,
} }];

// One output item per WhatsApp message to send (customer replies + staff alert).
const out = [];
const j = $json;
for (const r of (j.replies || [])) out.push({ json: { to: j.phone, text: r } });
if (j.staffAlert) {
  const staff = $('Merge Config').first().json.cfg.STAFF_WHATSAPP_NUMBER;
  if (staff) out.push({ json: { to: staff, text: j.staffAlert } });
}
return out;
